def test_stop_process() -> None:
    client = _create_client()
    client.post(
        "/api/v1/pipelines",
        headers=_auth_headers(),
        json={
            "pipeline_id": "proc_stop_me",
            "input_dataset_id": "ds_z",
            "dataflow": {
                "nodes": [{"subprocess_id": "F1", "subprocess_type": "FetchFeedItems"}],
                "edges": [],
            },
            "plugin_config": {},
        },
    )
    r = client.post(
        "/api/v1/pipelines/proc_stop_me/stop",
        headers=_auth_headers(),
        json={"reason": "test"},
    )
    assert r.status_code == 200
    assert r.json()["status"] == "stopped"
    assert r.json().get("cancelled_reason") == "test"

@pytest.mark.parametrize(
    "origin",
    [
        "https://x.dflowp.online",
        "https://dflowp.online",
        "https://foo-bar.baz.dflowp.online",
        "https://dflowp.online:8443",
        "http://app.dflowp.online:3000",
    ],
)
def test_cors_regex_allows_dflowp_online_variants(origin: str) -> None:
    assert _rx.fullmatch(origin) is not None, origin

@pytest.mark.parametrize(
    "origin",
    [
        "https://evil.com",
        "https://dflowp-online.evil.com",
        "https://notdflowp.online",
    ],
)
def test_cors_regex_rejects_unrelated_origins(origin: str) -> None:
    assert _rx.fullmatch(origin) is None, origin

def test_dataflow_get_descendants_including_self():
    """Descendants enthalten Knoten selbst und alle transitiven Nachfolger."""
    config = {
        "nodes": [
            {"subprocess_id": "A", "subprocess_type": "T"},
            {"subprocess_id": "B", "subprocess_type": "T"},
            {"subprocess_id": "C", "subprocess_type": "T"},
            {"subprocess_id": "D", "subprocess_type": "T"},
        ],
        "edges": [
            {"from": "A", "to": "B"},
            {"from": "B", "to": "C"},
            {"from": "A", "to": "D"},
        ],
    }
    df = parse_dataflow(config)

    assert df.get_descendants_including_self("A") == {"A", "B", "C", "D"}
    assert df.get_descendants_including_self("B") == {"B", "C"}
    assert df.get_descendants_including_self("C") == {"C"}

def test_dataflow_root_nodes_multiple():
    """Mehrere Root-Knoten werden alle erkannt."""
    config = {
        "nodes": [
            {"subprocess_id": "A", "subprocess_type": "T"},
            {"subprocess_id": "B", "subprocess_type": "T"},
            {"subprocess_id": "C", "subprocess_type": "T"},
        ],
        "edges": [
            {"from": "A", "to": "C"},
            {"from": "B", "to": "C"},
        ],
    }
    df = parse_dataflow(config)
    roots = set(df.get_root_nodes())

    assert roots == {"A", "B"}

def test_dataflow_successors_and_predecessors():
    """get_successors und get_predecessors funktionieren korrekt."""
    config = {
        "nodes": [
            {"subprocess_id": "A", "subprocess_type": "T"},
            {"subprocess_id": "B", "subprocess_type": "T"},
            {"subprocess_id": "C", "subprocess_type": "T"},
        ],
        "edges": [
            {"from": "A", "to": "B"},
            {"from": "A", "to": "C"},
        ],
    }
    df = parse_dataflow(config)

    assert set(df.get_successors("A")) == {"B", "C"}
    assert df.get_predecessors("B") == ["A"]
    assert df.get_predecessors("C") == ["A"]
    assert df.get_successors("B") == []
    assert df.get_successors("C") == []

def test_get_subprocess_unknown_type():
    """Unbekannter Typ liefert None zurück."""
    assert get_subprocess("NonExistentType_xyz") is None

@pytest.mark.asyncio
async def test_process_engine_external_event_notifications_without_local_subscriptions(
    isolated_event_service,
):
    """
    Wenn lokale Event-Subscriptions deaktiviert sind, kann die Engine
    Follow-up-Aktionen über handle_event_notification auslösen.
    """
    chain_config = ProcessConfiguration.from_dict(
        {
            "process_id": "proc_external_notify",
            "software_version": "1.0.0",
            "input_dataset_id": "ds_chain",
            "dataflow": {
                "nodes": [
                    {"subprocess_id": "Step1", "subprocess_type": "TypeA"},
                    {"subprocess_id": "Step2", "subprocess_type": "TypeB"},
                ],
                "edges": [{"from": "Step1", "to": "Step2"}],
            },
            "subprocess_config": {},
        }
    )

    process_repo = AsyncMock()
    process_repo.insert = AsyncMock(return_value="id")
    process_repo.insert_from_configuration = AsyncMock(
        return_value={
            "pipeline_id": "proc_external_notify",
            "dataflow_state_id": "dfs_ext",
            "status": "running",
        }
    )
    process_repo.update = AsyncMock(return_value=True)
    process_repo.find_by_id = AsyncMock(
        return_value={
            "pipeline_id": "proc_external_notify",
            "process_id": "proc_external_notify",
            "dataflow_state_id": "dfs_ext",
            "configuration": chain_config.to_dict(),
        }
    )

    dataflow_state_repo = AsyncMock()
    dataflow_state_repo.update_node_state = AsyncMock(return_value=True)
    dataflow_state_repo.get_dataflow_state = AsyncMock(
        return_value={
            "nodes": [
                {
                    "plugin_worker_id": "Step1",
                    "plugin_type": "TypeA",
                    "event_status": "EVENT_COMPLETED",
                    "io_transformation_states": [
                        {
                            "input_data_id": "d1",
                            "output_data_ids": ["out_step1"],
                            "status": "Finished",
                            "quality": 1.0,
                        }
                    ],
                },
                {
                    "plugin_worker_id": "Step2",
                    "plugin_type": "TypeB",
                    "event_status": "Not Started",
                    "io_transformation_states": [],
                },
            ],
            "edges": [{"from": "Step1", "to": "Step2"}],
        }
    )

    async def mock_find_data(data_id: str):
        return {"data_id": data_id, "content": {"text": data_id}, "type": "output"}

    data_repo = AsyncMock()
    data_repo.insert = AsyncMock()
    data_repo.find_by_id = mock_find_data

    dataset_repo = AsyncMock()
    dataset_repo.find_by_id = AsyncMock(
        return_value={"dataset_id": "ds_chain", "data_ids": ["d1"]}
    )

    started: list[str] = []

    async def mock_run(context, **kwargs):
        started.append(context.subprocess_id)
        return [
            IOTransformationState(
                input_data_id=context.input_data[0].data_id
                if context.input_data
                else "none",
                output_data_ids=["out_" + context.subprocess_id],
                status=TransformationStatus.FINISHED,
            )
        ]

    dummy = AsyncMock()
    dummy.run = mock_run

    engine = ProcessEngine(
        event_service=isolated_event_service,
        process_repository=process_repo,
        dataflow_state_repository=dataflow_state_repo,
        data_repository=data_repo,
        dataset_repository=dataset_repo,
        get_subprocess=lambda t: dummy,
        enable_local_event_subscriptions=False,
    )
    engine.start()

    await engine.start_process(chain_config)
    await asyncio.sleep(0.2)
    started.clear()

    await engine.handle_event_notification(
        {
            "process_id": "proc_external_notify",
            "subprocess_id": "Step1",
            "event_type": "EVENT_COMPLETED",
        }
    )
    await asyncio.sleep(0.2)

    assert "Step2" in started

@pytest.mark.asyncio
async def test_process_engine_subprocess_chaining(isolated_event_service):
    """Nach Abschluss von Subprozess A wird Subprozess B automatisch gestartet."""
    chain_config = ProcessConfiguration.from_dict(
        {
            "process_id": "proc_chain_test",
            "software_version": "1.0.0",
            "input_dataset_id": "ds_chain",
            "dataflow": {
                "nodes": [
                    {"subprocess_id": "Step1", "subprocess_type": "TypeA"},
                    {"subprocess_id": "Step2", "subprocess_type": "TypeB"},
                ],
                "edges": [{"from": "Step1", "to": "Step2"}],
            },
            "subprocess_config": {},
        }
    )

    process_repo = AsyncMock()
    process_repo.insert = AsyncMock(return_value="id")
    process_repo.insert_from_configuration = AsyncMock(
        return_value={
            "pipeline_id": "proc_chain_test",
            "dataflow_state_id": "dfs_chain",
            "status": "running",
        }
    )
    process_repo.update = AsyncMock(return_value=True)
    process_repo.find_by_id = AsyncMock(
        return_value={
            "pipeline_id": "proc_chain_test",
            "process_id": "proc_chain_test",
            "dataflow_state_id": "dfs_chain",
            "configuration": chain_config.to_dict(),
        }
    )

    dataflow_state_repo = AsyncMock()
    dataflow_state_repo.update_node_state = AsyncMock(return_value=True)
    dataflow_state_repo.get_dataflow_state = AsyncMock(
        return_value={
            "nodes": [
                {
                    "plugin_worker_id": "Step1",
                    "plugin_type": "TypeA",
                    "event_status": "EVENT_COMPLETED",
                    "io_transformation_states": [
                        {
                            "input_data_id": "d1",
                            "output_data_ids": ["out_step1"],
                            "status": "Finished",
                            "quality": 1.0,
                        }
                    ],
                },
                {
                    "plugin_worker_id": "Step2",
                    "plugin_type": "TypeB",
                    "event_status": "Not Started",
                    "io_transformation_states": [],
                },
            ],
            "edges": [{"from": "Step1", "to": "Step2"}],
        }
    )

    async def mock_find_data(data_id: str):
        return {"data_id": data_id, "content": {"text": data_id}, "type": "output"}

    data_repo = AsyncMock()
    data_repo.insert = AsyncMock()
    data_repo.find_by_id = mock_find_data

    dataset_repo = AsyncMock()
    dataset_repo.find_by_id = AsyncMock(
        return_value={"dataset_id": "ds_chain", "data_ids": ["d1"]}
    )

    started: list[str] = []

    async def mock_run(context, **kwargs):
        started.append(context.subprocess_id)
        return [
            IOTransformationState(
                input_data_id=context.input_data[0].data_id
                if context.input_data
                else "none",
                output_data_ids=["out_" + context.subprocess_id],
                status=TransformationStatus.FINISHED,
            )
        ]

    dummy = AsyncMock()
    dummy.run = mock_run

    engine = ProcessEngine(
        event_service=isolated_event_service,
        process_repository=process_repo,
        dataflow_state_repository=dataflow_state_repo,
        data_repository=data_repo,
        dataset_repository=dataset_repo,
        get_subprocess=lambda t: dummy,
    )
    engine.start()

    await engine.start_process(chain_config)
    await asyncio.sleep(0.3)

    assert "Step1" in started, "Step1 wurde nicht ausgeführt"
    assert "Step2" in started, "Step2 wurde nach Step1 nicht gestartet"
